// ---- shared helpers --------------------------------------------------------
// enemies within `r` of (x,y) that are alive and finished spawning
function itNear(world, x, y, r) {
  const out = [];
  const rr = r * r;
  for (const e of world.enemies) {
    if (e.dead || e.spawnT > 0) continue;
    if (dist2(x, y, e.x, e.y) < rr) out.push(e);
  }
  return out;
}
// uniform anvil feedback: rising label, gold flash text and a bright ring
function anvilFx(w, p, label) {
  w.particles.text(p.x, p.y - 18, label, { color: P.goldL, size: 14, weight: '900', life: 1.1 });
  w.particles.ring(p.x, p.y, P.goldL, 18, 110);
  w.particles.burst(p.x, p.y, 10, { color: [P.goldL, P.gold, '#fff'], speed: 70, size: 2, life: 0.45, glow: true });
  Sfx.play('levelup');
}

