// 1) 誘餌煙花 — pop a decoy flare: brief invulnerability/dash-window to slip
//    away, while yanking every drop on the field toward you.
Items.register({
  id: 'it_decoy_flare', name: '誘餌煙花', desc: '施放誘餌煙花，3 秒內免疫傷害並吸引場上所有掉落物', tier: 1, weight: 7, price: 24, icon: 'item_it_decoy_flare',
  use: (w, p) => {
    p.invuln = Math.max(p.invuln, 3);
    p.shieldT = Math.max(p.shieldT, 3);
    for (const pk of w.pickups) pk.magnet = true;
    w.particles.ring(p.x, p.y, P.emberL, 22, 150);
    w.particles.burst(p.x, p.y, 14, { color: [P.emberL, P.ember, '#fff'], speed: 120, size: 2.2, life: 0.45, glow: true });
    w.particles.text(p.x, p.y - 16, '誘餌！', { color: P.emberL, size: 13 });
    Sfx.play('dash');
    return true;
  },
});

// 2) 凝滯立場 — time-slow burst: violently staggers nearby foes by dumping
//    their momentum and shoving them outward, buying a breather.
Items.register({
  id: 'it_timeslow_burst', name: '凝滯立場', desc: '展開凝滯力場，大幅減速並震退周圍敵人，使其陷入短暫停滯', tier: 2, weight: 6, price: 36, icon: 'item_it_timeslow_burst',
  use: (w, p) => {
    const R = 130;
    const foes = itNear(w, p.x, p.y, R);
    for (const e of foes) {
      const a = Math.atan2(e.y - p.y, e.x - p.x);
      const k = 1 - (e.knockResist || 0);
      // kill momentum then apply a light outward shove (re-accel takes ~0.5s = stagger)
      e.vx = Math.cos(a) * 26 * k;
      e.vy = Math.sin(a) * 26 * k;
      if (e.charging) { e.charging = false; e.attackCd = Math.max(e.attackCd, 1.0); }
      w.particles.spawn({ x: e.x, y: e.y, life: 0.5, size: 3, color: P.ice, glow: true, drag: 0.9 });
    }
    fillCircleWorld(p.x, p.y, R, withAlpha(P.iceD, 0.12));
    w.particles.ring(p.x, p.y, P.ice, 26, R * 1.5);
    w.particles.ring(p.x, p.y, P.iceD, 18, R);
    w.particles.text(p.x, p.y - 16, '凝滯', { color: P.ice, size: 14 });
    Sfx.play('shard');
    return true;
  },
});

// 3) 鏈結療癒 — chain-heal: a surge of restorative shards that mends you and
//    leaves a few healing motes (hearts) at your feet. No-op refund on full HP.
Items.register({
  id: 'it_chain_heal', name: '鏈結療癒', desc: '立即回復 60 點生命，並在腳邊散出 2 顆治療之心', tier: 1, weight: 8, price: 26, icon: 'item_it_chain_heal',
  use: (w, p) => {
    if (p.hp >= p.maxHp) return false;
    p.heal(60);
    for (let i = 0; i < 2; i++) {
      const a = Math.random() * TAU, off = 8 + Math.random() * 12;
      w.addPickup('heart', p.x + Math.cos(a) * off, p.y + Math.sin(a) * off, 15);
    }
    w.particles.text(p.x, p.y - 16, '+60', { color: P.redL, size: 14 });
    w.particles.ring(p.x, p.y, P.redL, 14, 80);
    Sfx.play('heart');
    return true;
  },
});

