// small reusable anvil silhouette centred around (cx, base)
function itAnvilShape(p, body, bodyL, bodyD) {
  // top face
  p.rect(3, 5, 10, 2, body);
  p.rect(3, 5, 10, 1, bodyL);
  // horn (left beak) + step
  p.rect(2, 6, 2, 1, body);
  p.rect(12, 6, 1, 2, bodyD);
  // waist
  p.rect(6, 7, 4, 2, bodyD);
  // base
  p.rect(4, 9, 8, 2, body);
  p.rect(4, 10, 8, 1, bodyD);
}

